+#[derive(Debug, Clone)]
+pub struct LiveOracleConfig {
+    pub host: String,
+    pub port: u16,
+    pub io_timeout_ms: u64,
+    pub align_timing_from_fixture: bool,
+}
+
+impl Default for LiveOracleConfig {
+    fn default() -> Self {
+        Self {
+            host: "127.0.0.1".to_string(),
+            port: 6379,
+            io_timeout_ms: 2_000,
+            align_timing_from_fixture: true,
+        }
+    }
+}
